import os
import subprocess
import shlex

def create_backup(directory, format):
    # Validate the directory
    if not os.path.isdir(directory):
        raise ValueError("Invalid directory path")

    # Sanitize the directory path
    safe_directory = shlex.quote(directory)
    
    # Define the command based on the format
    if format == 'tar.gz':
        command = f"tar -czf {safe_directory}.tar.gz {safe_directory}"
    elif format == 'tar.bz2':
        command = f"tar -cjf {safe_directory}.tar.bz2 {safe_directory}"
    elif format == 'zip':
        command = f"zip -r {safe_directory}.zip {safe_directory}"
    elif format == '7z':
        command = f"7z a {safe_directory}.7z {safe_directory}"
    else:
        raise ValueError("Unsupported format")

    # Execute the command
    subprocess.run(command, shell=True, check=True)

